function clean(input) {
  if (!input) return '';
  if (typeof input === 'object') {
    input = input.content || input['#text'] || input.value || '';
  }
  if (typeof input !== 'string') input = String(input);
  return input.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

function detectLang(text) {
  if (!text || text.length < 20) return 'unknown';
  const fr = new Set(['le','la','les','un','une','des','est','sont','avec','pour','dans','sur','qui','que','ce','au','du','en','il','elle','nous','vous','ils','elles','pas','plus','par','ou','et','se','ne','si','de','je','tu','on','mais','donc','car','ni','or']);
  const en = new Set(['the','a','an','is','are','was','were','with','for','in','on','at','to','of','and','or','but','not','this','that','it','its','be','been','has','have','had','will','would','can','could','from','as','by','about','which','when','who','their','they','we','you','he','she']);
  const words = text.toLowerCase().split(/\W+/);
  let frScore = 0, enScore = 0;
  for (const w of words) {
    if (fr.has(w)) frScore++;
    if (en.has(w)) enScore++;
  }
  if (frScore + enScore < 4) return 'unknown';
  return frScore >= enScore ? 'fr' : 'en';
}

return items.flatMap(item => {
  const articles = item.json.items || [item.json];

  return articles.map(article => {
    const title = article.title || '';
    const summary = clean(article.contentSnippet || article.summary || article.content || '');
    const id = article.guid || article.id || title;
    const language = detectLang(title + ' ' + summary);

    return {
      json: {
        id,
        pageContent: `${title}\n\n${summary}`,
        metadata: {
          id,
          title,
          url: article.canonical?.[0]?.href || article.origin?.htmlUrl || article.url || article.link || '',
          source: article.source?.title || 'RSS',
          published_at: article.isoDate || article.published || null,
          language
        }
      }
    };
  });
});

const seen = new Set();

return items.filter(i => {
  const key = i.json.metadata.id || i.json.metadata.url;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const response = items[0].json.data;
// On cherche la ligne qui commence par "Auth=" et on prend la valeur
const authLine = response.split('\n').find(line => line.startsWith('Auth='));
const token = authLine ? authLine.split('=')[1] : '';

return [{
  json: {
    freshrss_token: token
  }
}];

return items.map((item, i) => {
  const embeddingData = item.json.data?.[0]?.embedding || item.json.embedding;
  if (!embeddingData) throw new Error(`No embedding in response for item ${i}: ` + JSON.stringify(item.json));

  // Get the original article from Dedup node (same index, same order)
  const article = $('Dedup').all()[i].json;

  // Format vector literal for pgvector
  const vectorStr = '[' + embeddingData.join(',') + ']';

  // Escape single quotes for SQL string literals
  const text = (article.pageContent || '').replace(/'/g, "''");
  const metadataJson = JSON.stringify(article.metadata || {}).replace(/'/g, "''");
  const articleId = (article.metadata?.id || '').replace(/'/g, "''");

  const sqlQuery = `INSERT INTO rss_articles (text, metadata, embedding)
  SELECT '${text}', '${metadataJson}'::jsonb, '${vectorStr}'::vector
  WHERE NOT EXISTS (
    SELECT 1 FROM rss_articles WHERE metadata->>'id' = '${articleId}'
  )`;

  return {
    json: {
      sqlQuery,
      title: article.metadata?.title
    }
  };
});

// Split comma-separated interests into individual items, one per embedding call
const text = $json.centers_of_interest || '';
const interests = text.split(',').map(s => s.trim()).filter(Boolean);

return interests.map(interest => ({ json: { interest } }));

// Build one cosine-distance SQL query per interest embedding
return items.map(item => {
  const vectorArray = item.json.data?.[0]?.embedding || item.json.embedding;
  if (!vectorArray) throw new Error('No embedding found in response: ' + JSON.stringify(item.json));

  // <=> is cosine distance — correct metric for sentence transformers
  const formattedVector = '[' + vectorArray.map(n => Number(n.toFixed(6))).join(',') + ']';

  const query = `
    SELECT
      id,
      text AS contenu,
      metadata->>'title' AS titre,
      metadata->>'url' AS lien,
      metadata->>'published_at' AS date_publication,
      metadata->>'language' AS language,
      (embedding <=> '${formattedVector}'::vector)
        * CASE WHEN metadata->>'language' = 'fr' THEN 0.75 ELSE 1.0 END AS distance
    FROM rss_articles
    WHERE inserted_at > NOW() - INTERVAL '25 hours'
    ORDER BY distance ASC
    LIMIT 5
  `;

  return { json: { sqlQuery: query } };
});

// Deduplicate articles across all interest queries, keep the closest distance per article
const seen = new Map();
for (const item of items) {
  const id = String(item.json.id);
  const dist = parseFloat(item.json.distance);
  if (!seen.has(id) || dist < seen.get(id).distance) {
    seen.set(id, { ...item.json, distance: dist });
  }
}

const articles = [...seen.values()]
  .sort((a, b) => a.distance - b.distance)
  .slice(0, 10)
  .map(a => ({
    titre: a.titre || 'Sans titre',
    lien: a.lien || '',
    contenu: a.contenu || 'Pas de contenu disponible',
    date_publication: a.date_publication || ''
  }));

if (articles.length === 0) {
  throw new Error('Aucun article trouvé dans les 30 derniers jours. La base est peut-être vide.');
}

return [{ json: { articles } }];

